syntax = "proto3";
package market.v1;

import "google/protobuf/timestamp.proto";

message Quote {
  string symbol = 1;
  double bid = 2;
  double ask = 3;
  int64 volume = 4;
  google.protobuf.Timestamp as_of = 5;
}

message SubscribeRequest {
  repeated string symbols = 1;
}

service PriceFeed {
  // Server-streaming: client subscribes once, server pushes quotes.
  rpc Subscribe(SubscribeRequest) returns (stream Quote);
}

// Server-streaming handler in Go.
func (s *feedServer) Subscribe(req *pb.SubscribeRequest, stream pb.PriceFeed_SubscribeServer) error {
  ch := s.bus.Subscribe(req.GetSymbols())
  defer s.bus.Unsubscribe(ch)

  for {
    select {
    case <-stream.Context().Done():
      // Client cancelled or deadline expired.
      return stream.Context().Err()
    case q, ok := <-ch:
      if !ok {
        return nil // bus closed
      }
      if err := stream.Send(q); err != nil {
        return err // transport error / client gone
      }
    }
  }
}

ctx, cancel := context.WithTimeout(context.Background(), 500*time.Millisecond)
defer cancel() // always cancel to release resources, even on success

resp, err := client.PlaceOrder(ctx, &pb.OrderRequest{Symbol: "ACME", Qty: 10})
if err != nil {
  if status.Code(err) == codes.DeadlineExceeded {
    // budget exhausted somewhere downstream
  }
  return err
}

// Server-side unary interceptor: auth + latency metric.
func authMetricsInterceptor(
  ctx context.Context, req interface{},
  info *grpc.UnaryServerInfo, handler grpc.UnaryHandler,
) (interface{}, error) {
  md, _ := metadata.FromIncomingContext(ctx)
  if !validToken(md.Get("authorization")) {
    return nil, status.Error(codes.Unauthenticated, "invalid token")
  }
  start := time.Now()
  resp, err := handler(ctx, req)
  rpcLatency.WithLabelValues(info.FullMethod, status.Code(err).String()).
    Observe(time.Since(start).Seconds())
  return resp, err
}

srv := grpc.NewServer(grpc.ChainUnaryInterceptor(
  recoveryInterceptor, authMetricsInterceptor,
))

message Quote {
  string symbol = 1;
  double bid = 2;
  double ask = 3;
  reserved 4;                 // old 'volume' field removed; number 4 is now poison
  reserved "volume";          // also reserve the name to prevent reuse
  google.protobuf.Timestamp as_of = 5;
  string exchange = 6;        // new field: safe, uses a brand-new number
}

// BAD: unbounded buffering, ignores backpressure.
func (s *feedServer) Subscribe(req *pb.SubscribeRequest, stream pb.PriceFeed_SubscribeServer) error {
  ch := make(chan *pb.Quote) // unbounded fan-in below
  go s.bus.FirehoseInto(ch, req.GetSymbols())
  for q := range ch {
    stream.Send(q) // blocks on slow client while ch keeps filling -> OOM
  }
  return nil
}

// GOOD: bounded buffer + conflation; drop stale quotes for slow clients.
func (s *feedServer) Subscribe(req *pb.SubscribeRequest, stream pb.PriceFeed_SubscribeServer) error {
  buf := make(chan *pb.Quote, 256) // bounded
  sub := s.bus.Subscribe(req.GetSymbols(), buf, conflateBySymbol)
  defer sub.Close()
  for {
    select {
    case <-stream.Context().Done():
      return stream.Context().Err()
    case q := <-buf:
      if err := stream.Send(q); err != nil {
        return err
      }
    }
  }
}

