// price_feed.proto
syntax = "proto3";
package market.v1;
import "google/protobuf/timestamp.proto";

message Quote {
  string symbol = 1;
  double bid = 2;
  double ask = 3;
  google.protobuf.Timestamp as_of = 4;
}
message SubscribeRequest { repeated string symbols = 1; }

service PriceFeed {
  rpc Subscribe(SubscribeRequest) returns (stream Quote);
}

// server.go
package feed

import (
  "context"
  pb "example.com/market/v1"
)

type Bus interface {
  // Subscribe returns a channel of conflated quotes and a cancel func.
  Subscribe(symbols []string) (<-chan *pb.Quote, func())
}

type Server struct {
  pb.UnimplementedPriceFeedServer
  Bus Bus
}

func (s *Server) Subscribe(req *pb.SubscribeRequest, stream pb.PriceFeed_SubscribeServer) error {
  if len(req.GetSymbols()) == 0 {
    return status.Error(codes.InvalidArgument, "symbols required")
  }
  // Bus internally conflates by symbol into a BOUNDED channel.
  quotes, cancel := s.Bus.Subscribe(req.GetSymbols())
  defer cancel() // clean up on any return path

  ctx := stream.Context()
  for {
    select {
    case <-ctx.Done():
      return ctx.Err() // deadline exceeded or client cancelled
    case q, ok := <-quotes:
      if !ok {
        return nil // bus closed gracefully
      }
      if err := stream.Send(q); err != nil {
        return err // client gone / transport error
      }
    }
  }
}

// conflatingBus: bounded buffer + latest-wins per symbol.
func (b *memBus) fanOut(sub *subscriber) {
  latest := map[string]*pb.Quote{}
  for q := range sub.raw {
    latest[q.Symbol] = q // overwrite stale tick
    select {
    case sub.out <- latest[q.Symbol]: // delivered
      delete(latest, q.Symbol)
    default:
      // consumer behind: keep only the newest, drop nothing extra,
      // it will be sent on the next non-blocking opportunity.
    }
  }
  close(sub.out)
}

syntax = "proto3";
package account.v1;

message User {
  string id = 1;
  string display_name = 2;

  // (a) ssn removed for compliance. We MUST reserve 3 forever so no
  // future field reuses the number and misreads old persisted data.
  reserved 3;
  reserved "ssn";

  // (b) new field, brand-new number. Old writers omit it; new readers
  // see the proto3 default `false`, which is the safe interpretation.
  bool email_verified = 4;

  // (c) another new, never-before-used number. Old readers seeing this
  // field simply skip the unknown tag and preserve it on re-serialize.
  string phone = 5;
}
